#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifndef class_T
#define class_T float
#endif

#ifndef BLOCK_STRIDED
#define BLOCK_STRIDED 0
#endif

#ifndef ENABLE_DP
#define ENABLE_DP 0
#endif

#ifndef ENABLE_HP
#define ENABLE_HP 0
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#if ENABLE_HP
typedef struct {
    half x;
    half y;
} half2;
#endif

__attribute__((noinline))
class_T bench_block(class_T* data, class_T f) {
    class_T sum = 0;

    #if COMPUTE_ITERATIONS == 0
        sum = data[0];
    #else
        class_T t = data[0];
        for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
            t = t * t + f;
        }
        sum = t;

        for (int i = 1; i < ELEMENTS_PER_THREAD; i++) {
            t = data[i];
            for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
                t = t * t + f;
            }
            sum += t;
        }
    #endif

    return sum;
}

__kernel void benchmark_func(class_T seed, __global class_T* src) {
    size_t idx = get_global_id(0);
    size_t stride = get_global_size(0);

    #if BLOCK_STRIDED
        stride = get_local_size(0) * get_num_groups(0);
    #endif

    size_t global_offset = idx * ELEMENTS_PER_THREAD * FUSION_DEGREE;

    class_T local_sum = 0;

    for (int f = 0; f < FUSION_DEGREE; f++) {
        size_t base_idx = global_offset + f * ELEMENTS_PER_THREAD;
        class_T f_val = seed;

        class_T block_sum = 0;
        class_T t[ELEMENTS_PER_THREAD];

        #pragma clang loop vectorize(enable)
        for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
            t[i] = src[base_idx + i];
        }

        #if COMPUTE_ITERATIONS > 0
            for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
                #pragma clang loop vectorize(enable)
                for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
                    t[i] = t[i] * t[i] + f_val;
                }
            }
        #endif

        #pragma clang loop vectorize(enable)
        for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
            block_sum += t[i];
        }

        local_sum += block_sum;
    }

    src[idx] = local_sum;
}
